function report = runHeightLabelDensityStudy(options)
%RUNHEIGHTLABELDENSITYSTUDY Frozen projected-motion label-density study.
%
% Each scene is rendered once. Candidate height grids share the fixture's
% exact search bounds and are spaced by a target median projected motion.
% Oracle discrete quantization, raw ZNCC WTA, guarded sublabel refinement,
% and frozen physical-height SGM are evaluated separately.
%
% Traceability: algo/main.tex Algorithm 1, Eqs. (52)--(55), (68)--(76),
% (121)--(133), and Secs. 10.4--10.5, 11.2--11.4, 14.6;
% long-range workplan P1; implementation plan P1 steps 1--3.

arguments
    options.Mode (1, 1) string ...
        {mustBeMember(options.Mode, ["tuning", "heldout"])} = "tuning"
    options.StudyFile (1, 1) string = ""
    options.Display (1, 1) logical = true
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
if strlength(options.StudyFile) == 0
    options.StudyFile = fullfile(root, "config", "synthetic", ...
        "height_label_density_study_v4.json");
end
if ~isfile(options.StudyFile)
    error("runHeightLabelDensityStudy:StudyNotFound", ...
        "Study manifest does not exist: %s", options.StudyFile);
end
study = jsondecode(fileread(options.StudyFile));
validateStudy(study);
heldoutReady = ismember(string(study.state), ...
    ["policy-frozen", "failure-diagnostics-preregistered"]);
if options.Mode == "heldout" && ~heldoutReady
    error("runHeightLabelDensityStudy:PolicyNotFrozen", ...
        "Held-out fixtures remain inaccessible until the manifest state " ...
        + "is policy-frozen and contains frozenPolicy.");
end
failureCalibrator = [];
if isfield(study, "failureDetection")
    failureCalibrator = HeightConfidenceCalibrator.fromStruct( ...
        study.failureDetection.frozenConfidence);
end

if options.Mode == "tuning"
    fixtureNames = string(study.tuningFixtures(:));
    expectedSuite = "tuning";
else
    fixtureNames = string(study.heldoutFixtures(:));
    expectedSuite = "heldout";
end
folder = fileparts(options.StudyFile);
sceneResults = cell(numel(fixtureNames), 1);
runtime = cell(numel(fixtureNames), 1);
strata = cell(numel(fixtureNames), 1);
sceneDiagnostics = cell(numel(fixtureNames), 1);
failureDiagnostics = cell(numel(fixtureNames), 1);
totalTimer = tic;
for k = 1:numel(fixtureNames)
    fixture = resolveFixture(folder, fixtureNames(k));
    [sceneResults{k}, runtime{k}, strata{k}, sceneDiagnostics{k}, ...
        failureDiagnostics{k}] = evaluateScene( ...
        fixture, study, expectedSuite, failureCalibrator, options);
end
results = vertcat(sceneResults{:});
runtime = vertcat(runtime{:});
strata = vertcat(strata{:});
sceneDiagnostics = vertcat(sceneDiagnostics{:});
failureDiagnostics = vertcat(failureDiagnostics{:});

if options.Mode == "tuning"
    recommendation = recommendPolicy(results, study);
else
    recommendation = assessFrozenPolicy(results, study);
end
forecast = forecastFullFormat(results, runtime, study, recommendation);
figures = struct;
if options.Display
    figures = displayStudy(results, runtime, recommendation, options.Mode);
end
report = struct( ...
    "Mode", options.Mode, ...
    "StudyIdentifier", string(study.identifier), ...
    "StudyFile", options.StudyFile, ...
    "StudyState", string(study.state), ...
    "FixtureIdentifiers", unique(results.Scene, "stable"), ...
    "TargetProjectedMotionPixels", ...
    double(study.targetProjectedMotionPixels(:)).', ...
    "IncludeThreePlaneControl", logical(study.includeThreePlaneControl), ...
    "Results", results, ...
    "Runtime", runtime, ...
    "StratifiedResults", strata, ...
    "SceneDiagnostics", sceneDiagnostics, ...
    "FailureDiagnostics", failureDiagnostics, ...
    "Recommendation", recommendation, ...
    "FullFormatForecast", forecast, ...
    "TotalSeconds", toc(totalTimer), ...
    "Figures", figures, ...
    "HeldoutAccessed", options.Mode == "heldout", ...
    "Interpretation", ...
    "P1 study only; hierarchy and adaptive local labels are not implemented");
printStudy(report);
clear cleanup
end

function [results, runtime, strata, diagnostic, failure] = evaluateScene( ...
        fixture, study, expectedSuite, failureCalibrator, options)
sceneTimer = tic;
c = jsondecode(fileread(fixture));
if string(c.suite) ~= expectedSuite
    error("runHeightLabelDensityStudy:SuiteMismatch", ...
        "Fixture %s is %s, expected %s.", ...
        string(c.identifier), string(c.suite), expectedSuite);
end
renderer = SyntheticPinholeRenderer.fromJson(fixture);
pair = renderer.renderPair;
r = c.movingRadiometry;
pair.MovingImage = SyntheticRadiometry.apply( ...
    pair.MovingImage, renderer.BitDepth, string(r.kind), ...
    Gain=double(r.gain), Offset=double(r.offset), ...
    Gamma=double(r.gamma), BlurSigmaPixels=double(r.blurSigmaPixels), ...
    NoiseSigma=double(r.noiseSigma), Seed=double(r.seed));
truth = sceneTruth(renderer, pair);
geometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
precision = string(study.dense.workingPrecision);
levels = 2 ^ renderer.BitDepth - 1;
reference = cast(pair.ReferenceImage, precision) ./ cast(levels, precision);
moving = cast(pair.MovingImage, precision) ./ cast(levels, precision);
curve = HeightCostCurve(geometry, reference, moving, ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    PrepareGradients=false, WorkingPrecision=precision);
dense = DenseHeightSweep(curve);
attribute = sceneAttributes(geometry, double(reference), truth, study);
specification = labelSpecifications(renderer.SearchRangeMetres, ...
    attribute.MedianObservabilityPixelsPerMetre, study);

modeResults = cell(height(specification), 1);
modeRuntime = cell(height(specification), 1);
modeStrata = cell(height(specification), 1);
modeFailure = cell(height(specification), 1);
for k = 1:height(specification)
    [modeResults{k}, modeRuntime{k}, modeStrata{k}, modeFailure{k}] = ...
        evaluateLabels( ...
        string(c.identifier), dense, truth, attribute, ...
        specification(k, :), study, renderer.ImageSize, ...
        failureCalibrator, options);
end
results = vertcat(modeResults{:});
runtime = vertcat(modeRuntime{:});
strata = vertcat(modeStrata{:});
failure = vertcat(modeFailure{:});
diagnostic = table( ...
    string(c.identifier), expectedSuite, renderer.SurfaceType, ...
    string(r.kind), renderer.TextureType, renderer.ImageSize(1), ...
    renderer.ImageSize(2), mean(truth.Valid, "all"), ...
    attribute.MedianObservabilityPixelsPerMetre, ...
    finitePercentile(attribute.ObservabilityPixelsPerMetre, 10), ...
    finitePercentile(attribute.ObservabilityPixelsPerMetre, 90), ...
    finiteStatistic(attribute.TrajectoryCurvature, @median), ...
    mean(attribute.NearHeightDiscontinuity & truth.Valid, "all"), ...
    mean(attribute.NearOcclusionBoundary & truth.Valid, "all"), ...
    toc(sceneTimer), ...
    VariableNames=["Scene", "Suite", "SurfaceType", "Radiometry", ...
    "TextureType", "Rows", "Columns", "TruthValidFraction", ...
    "MedianObservabilityPixelsPerMetre", ...
    "P10ObservabilityPixelsPerMetre", ...
    "P90ObservabilityPixelsPerMetre", ...
    "MedianTrajectoryCurvature", ...
    "NearHeightDiscontinuityFraction", ...
    "NearOcclusionBoundaryFraction", "SceneTotalSeconds"]);
end

function [results, runtime, strata, failure] = evaluateLabels( ...
        scene, dense, truth, attribute, specification, study, imageSize, ...
        failureCalibrator, options)
z = specification.HeightLabelsMetres{1};
mode = specification.LabelMode;
target = specification.TargetProjectedMotionPixels;
minimumSupport = double(study.dense.minimumSupportFraction);
timer = tic;
raw = dense.runZnccOptimized(z, ...
    TileSize=double(study.dense.tileSize), ...
    LabelBlockSize=double(study.dense.labelBlockSize), ...
    StoreCostVolumes=true, UseParallel=options.UseParallel, ...
    NumWorkers=options.NumWorkers, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    WorkingPrecision=string(study.dense.workingPrecision), ...
    Products=["LabelIndex", "BestCost", "SecondBestCost", ...
    "NeighborCosts", "Margin", "Curvature", "ValidLabelCount", ...
    "Observability", "Correspondence"], ...
    MinimumSupportFraction=minimumSupport);
znccSeconds = toc(timer);

timer = tic;
refined = HeightSublabelRefiner.refine(z, raw.LabelIndex, ...
    raw.PreviousLabelCost, raw.BestCost, raw.NextLabelCost, ...
    ValidMask=raw.Valid);
refinedProjection = dense.projectHeightMap( ...
    refined.RefinedHeightMetres, refined.Valid);
refinementSeconds = toc(timer);

timer = tic;
p = study.sgm;
sgm = HeightSgm.aggregateVectorized(raw.CostVolume, z, ...
    PenaltyPerMetre=double(p.penaltyPerMetre), ...
    MaximumPenalty=double(p.maximumPenalty), ...
    DirectionCount=double(p.directionCount));
sgmProjection = dense.projectHeightMap(sgm.HeightMetres, sgm.Valid);
sgmSeconds = toc(timer);

[oracleHeight, oracleIndex, oracleValid] = nearestLabel( ...
    truth.HeightMetres, truth.Valid, z);
oracleProjection = dense.projectHeightMap(oracleHeight, oracleValid);
method = struct( ...
    "Name", {"oracle-discrete", "raw-ZNCC", "guarded-sublabel", ...
    "frozen-SGM"}, ...
    "ErrorComponent", {"label quantization lower bound", ...
    "quantization plus data term", ...
    "data term plus guarded interpolation", ...
    "quantization plus data term plus regularization"}, ...
    "Height", {oracleHeight, raw.HeightMetres, ...
    refined.RefinedHeightMetres, sgm.HeightMetres}, ...
    "Correspondence", {oracleProjection.CorrespondenceXY, ...
    raw.CorrespondenceXY, refinedProjection.CorrespondenceXY, ...
    sgmProjection.CorrespondenceXY}, ...
    "Valid", {oracleProjection.Valid, raw.Valid, ...
    refinedProjection.Valid, sgmProjection.Valid}, ...
    "LabelIndex", {oracleIndex, raw.LabelIndex, raw.LabelIndex, ...
    sgm.LabelIndex});
results = methodTable(scene, mode, target, z, method, truth, raw, ...
    refined, sgm, study);
strata = stratifiedTable(scene, mode, target, method, truth, attribute, ...
    double(study.metrics.badPixelThresholdPixels));
failure = table;
if isfield(study, "failureDetection")
    fd = study.failureDetection;
    final = struct("Valid", sgmProjection.Valid, ...
        "LabelIndex", sgm.LabelIndex, ...
        "CorrespondenceXY", sgmProjection.CorrespondenceXY);
    oracle = struct("Valid", oracleProjection.Valid, ...
        "CorrespondenceXY", oracleProjection.CorrespondenceXY);
    failure = HeightLabelFailureDiagnostics.assess( ...
        scene, mode, target, z, raw, final, oracle, truth, attribute, ...
        failureCalibrator, ...
        BadPixelThresholdPixels=double(fd.badPixelThresholdPixels), ...
        LowConfidenceSigmaPixels=double( ...
        fd.lowConfidenceSigmaPixelsThreshold), ...
        MaximumQuantizationErrorPixels=double( ...
        fd.maximumLocalQuantizationErrorPixels), ...
        HighTrajectoryCurvatureQuantile=double( ...
        fd.highTrajectoryCurvatureQuantile));
end

costInfo = whos("raw");
penalty = diag(sgm.PairwisePenalty, 1);
runtime = table(scene, mode, target, numel(z), z(1), z(end), ...
    specification.ActualMedianProjectedMotionPixels, ...
    prod(imageSize) .* numel(z), znccSeconds, refinementSeconds, ...
    sgmSeconds, znccSeconds + refinementSeconds + sgmSeconds, ...
    raw.Runtime.PixelLabelsPerSecond, raw.Runtime.OutputArrayBytes, ...
    numel(raw.CostVolume) .* precisionBytes(class(raw.CostVolume)), ...
    sgm.TrackedArrayBytes, sgm.MaximumScanlineStateBytes, ...
    costInfo.bytes, mean(penalty >= double(p.maximumPenalty)), ...
    VariableNames=["Scene", "LabelMode", ...
    "TargetProjectedMotionPixels", "LabelCount", ...
    "MinimumHeightMetres", "MaximumHeightMetres", ...
    "ActualMedianProjectedMotionPixels", "PixelLabelEvaluations", ...
    "ZnccSeconds", "RefinementSeconds", "SgmSeconds", ...
    "AlgorithmSeconds", "PixelLabelsPerSecond", ...
    "RawOutputBytes", "CostVolumeBytes", "SgmTrackedArrayBytes", ...
    "SgmMaximumScanlineStateBytes", "RawStructureBytes", ...
    "SgmAdjacentPenaltySaturationFraction"]);
end

function result = methodTable(scene, mode, target, z, method, truth, ...
        raw, refined, sgm, study)
n = numel(method);
rows = cell(n, 18);
for k = 1:n
    metric = methodMetric(method(k).Height, method(k).Correspondence, ...
        method(k).Valid, truth, ...
        double(study.metrics.badPixelThresholdPixels));
    if method(k).Name == "guarded-sublabel"
        refinementSupport = nnz(refined.Valid) ./ max(nnz(raw.Valid), 1);
    else
        refinementSupport = NaN;
    end
    if method(k).Name == "frozen-SGM"
        penalty = diag(sgm.PairwisePenalty, 1);
        penaltySaturation = mean( ...
            penalty >= double(study.sgm.maximumPenalty));
    else
        penaltySaturation = NaN;
    end
    valid = method(k).Valid & method(k).LabelIndex > 0;
    boundary = valid & (method(k).LabelIndex == 1 ...
        | method(k).LabelIndex == numel(z));
    boundaryFraction = nnz(boundary) ./ max(nnz(valid), 1);
    rows(k, :) = {scene, mode, target, numel(z), method(k).Name, ...
        method(k).ErrorComponent, metric.Coverage, ...
        metric.HeightMaeMetres, metric.HeightRmseMetres, ...
        metric.MedianEpePixels, metric.EpeRmsePixels, ...
        metric.P95EpePixels, metric.BadPixelFraction, ...
        boundaryFraction, refinementSupport, penaltySaturation, ...
        z(1), z(end)};
end
result = cell2table(rows, VariableNames=["Scene", "LabelMode", ...
    "TargetProjectedMotionPixels", "LabelCount", "Method", ...
    "ErrorComponent", "Coverage", "HeightMaeMetres", ...
    "HeightRmseMetres", "MedianEpePixels", "EpeRmsePixels", ...
    "P95EpePixels", "BadPixelFraction", "BoundaryWinnerFraction", ...
    "RefinementSupportFraction", "SgmPenaltySaturationFraction", ...
    "MinimumHeightMetres", "MaximumHeightMetres"]);
end

function result = stratifiedTable(scene, mode, target, method, truth, ...
        attribute, badThreshold)
values = {attribute.ObservabilityPixelsPerMetre, ...
    attribute.TrajectoryCurvature, attribute.TextureLocalStandardDeviation, ...
    attribute.HeightDiscontinuityDistancePixels, ...
    attribute.OcclusionBoundaryDistancePixels};
names = ["observability", "trajectory-curvature", "texture", ...
    "height-discontinuity-distance", "occlusion-boundary-distance"];
bins = cell(size(values));
for k = 1:3
    bins{k} = tertileBins(values{k}, truth.Valid);
end
bins{4} = boundaryBins(values{4}, truth.Valid);
bins{5} = boundaryBins(values{5}, truth.Valid);
rows = cell(numel(method) .* numel(values) .* 3, 14);
row = 0;
for k = 1:numel(method)
    for j = 1:numel(values)
        for b = 1:3
            row = row + 1;
            stratum = truth.Valid & bins{j} == b;
            metric = methodMetric(method(k).Height, ...
                method(k).Correspondence, method(k).Valid & stratum, ...
                truthWithValid(truth, stratum), badThreshold);
            x = values{j}(stratum & isfinite(values{j}));
            rows(row, :) = {scene, mode, target, method(k).Name, ...
                names(j), b, nnz(stratum), finiteStatistic(x, @min), ...
                finiteStatistic(x, @max), metric.Coverage, ...
                metric.HeightRmseMetres, metric.EpeRmsePixels, ...
                metric.P95EpePixels, metric.BadPixelFraction};
        end
    end
end
result = cell2table(rows, VariableNames=["Scene", "LabelMode", ...
    "TargetProjectedMotionPixels", "Method", "Variable", "Bin", ...
    "TruthPixelCount", "BinMinimum", "BinMaximum", "Coverage", ...
    "HeightRmseMetres", "EpeRmsePixels", "P95EpePixels", ...
    "BadPixelFraction"]);
end

function metric = methodMetric(height, correspondence, valid, truth, bad)
valid = valid & truth.Valid & isfinite(height) ...
    & isfinite(correspondence(:, :, 1)) ...
    & isfinite(correspondence(:, :, 2));
coverage = nnz(valid) ./ max(nnz(truth.Valid), 1);
dh = height(valid) - truth.HeightMetres(valid);
wx = correspondence(:, :, 1);
wy = correspondence(:, :, 2);
tx = truth.CorrespondenceXY(:, :, 1);
ty = truth.CorrespondenceXY(:, :, 2);
epe = hypot(wx(valid) - tx(valid), wy(valid) - ty(valid));
metric = struct( ...
    "Coverage", coverage, ...
    "HeightMaeMetres", finiteStatistic(abs(dh), @mean), ...
    "HeightRmseMetres", sqrt(finiteStatistic(dh .^ 2, @mean)), ...
    "MedianEpePixels", finiteStatistic(epe, @median), ...
    "EpeRmsePixels", sqrt(finiteStatistic(epe .^ 2, @mean)), ...
    "P95EpePixels", finitePercentile(epe, 95), ...
    "BadPixelFraction", finiteStatistic(epe > bad, @mean));
end

function specification = labelSpecifications(range, observability, study)
target = double(study.targetProjectedMotionPixels(:));
count = ceil(diff(range) .* observability ./ target) + 1;
count = max(count, 3);
mode = repmat("projected-motion", numel(target), 1);
if logical(study.includeThreePlaneControl)
    target = [target; NaN];
    count = [count; 3];
    mode = [mode; "three-plane"];
end
labels = cell(numel(count), 1);
actual = nan(numel(count), 1);
for k = 1:numel(count)
    labels{k} = linspace(range(1), range(2), count(k));
    actual(k) = diff(range) ./ (count(k) - 1) .* observability;
end
specification = table(mode, target, count, actual, labels, ...
    VariableNames=["LabelMode", "TargetProjectedMotionPixels", ...
    "LabelCount", "ActualMedianProjectedMotionPixels", ...
    "HeightLabelsMetres"]);
end

function attribute = sceneAttributes(geometry, reference, truth, study)
[y, x] = ndgrid(1:size(reference, 1), 1:size(reference, 2));
p = [x(:), y(:)];
h = truth.HeightMetres(:);
[~, kappa, vk] = geometry.heightDerivative(p, h, DeltaHeight=0.5);
kappa(~vk) = NaN;
d = 5;
[wm, vm] = geometry.warp(p, h - d);
[w0, v0] = geometry.warp(p, h);
[wp, vp] = geometry.warp(p, h + d);
curvature = vecnorm(wp - 2 .* w0 + wm, 2, 2) ...
    ./ max(vecnorm(wp - wm, 2, 2), eps);
curvature(~(vm & v0 & vp)) = NaN;

mask = truth.ReferenceValid;
n = conv2(double(mask), ones(5), "same");
image = reference;
image(~mask) = 0;
sx = conv2(image, ones(5), "same");
sxx = conv2(image .^ 2, ones(5), "same");
variance = max(0, sxx ./ max(n, 1) - (sx ./ max(n, 1)) .^ 2);
texture = sqrt(variance);
texture(n < 20) = NaN;

height = truth.HeightMetres;
finiteHeight = isfinite(height) & truth.ReferenceValid;
hi = height;
lo = height;
hi(~finiteHeight) = -Inf;
lo(~finiteHeight) = Inf;
hi = movmax(movmax(hi, 3, 1), 3, 2);
lo = movmin(movmin(lo, 3, 1), 3, 2);
heightBoundary = finiteHeight & hi - lo ...
    > double(study.metrics.heightDiscontinuityThresholdMetres);
occlusionBoundary = truth.Valid & conv2(double(~truth.Valid), ...
    ones(3), "same") > 0;
heightDistance = bwdist(heightBoundary);
occlusionDistance = bwdist(occlusionBoundary);
attribute = struct( ...
    "ObservabilityPixelsPerMetre", reshape(kappa, size(reference)), ...
    "MedianObservabilityPixelsPerMetre", median(kappa(vk)), ...
    "TrajectoryCurvature", reshape(curvature, size(reference)), ...
    "TextureLocalStandardDeviation", texture, ...
    "HeightDiscontinuityDistancePixels", heightDistance, ...
    "OcclusionBoundaryDistancePixels", occlusionDistance, ...
    "NearHeightDiscontinuity", heightDistance <= ...
    double(study.metrics.nearBoundaryPixels), ...
    "NearOcclusionBoundary", occlusionDistance <= ...
    double(study.metrics.nearBoundaryPixels));
end

function [height, index, valid] = nearestLabel(truth, truthValid, z)
edge = [-Inf, (z(1:(end - 1)) + z(2:end)) ./ 2, Inf];
index = discretize(truth, edge);
valid = truthValid & truth >= z(1) & truth <= z(end) & isfinite(index);
height = nan(size(truth));
height(valid) = z(index(valid));
index(~valid) = 0;
end

function truth = sceneTruth(renderer, pair)
[y, x] = ndgrid(1:renderer.ImageSize(1), 1:renderer.ImageSize(2));
p = [x(:), y(:)];
if renderer.SurfaceType == "step"
    [~, z, vr] = PinholeStepOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [w, vg, inside, visible] = PinholeStepOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.StepHeightMetres, ...
        renderer.StepDirectionENU, ...
        PositionMetres=renderer.StepPositionMetres);
    valid = vr & vg & inside & visible;
elseif renderer.SurfaceType == "radial-sinc"
    [~, z, vr] = PinholeSincOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SincAmplitudeMetres, renderer.SincLobeSpacingMetres, ...
        CenterENU=renderer.SincCenterENU);
    [w, vg, inside, visible] = PinholeSincOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SincAmplitudeMetres, ...
        renderer.SincLobeSpacingMetres, CenterENU=renderer.SincCenterENU);
    valid = vr & vg & inside & visible;
elseif renderer.SurfaceType == "hillside-buildings"
    [~, z, vr] = PinholeHillsideBuildingsOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU, renderer.TerrainCurvaturePerMetre, ...
        renderer.Buildings, CurvatureCenterENU=renderer.CurvatureCenterENU);
    [w, vg, inside, visible] = ...
        PinholeHillsideBuildingsOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU, ...
        renderer.TerrainCurvaturePerMetre, renderer.Buildings, ...
        CurvatureCenterENU=renderer.CurvatureCenterENU);
    valid = vr & vg & inside & visible;
else
    [z, ~, ~, vr] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [w, vg, inside] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    valid = vr & vg & inside;
end
referenceValid = vr & pair.ReferenceValid(:);
movingSupport = interp2(double(pair.MovingValid), w(:, 1), w(:, 2), ...
    "linear", 0) >= 1 - 64 .* eps;
valid = valid & referenceValid & movingSupport;
z(~referenceValid) = NaN;
w(~valid, :) = NaN;
truth = struct( ...
    "HeightMetres", reshape(z, renderer.ImageSize), ...
    "CorrespondenceXY", reshape(w, [renderer.ImageSize, 2]), ...
    "ReferenceValid", reshape(referenceValid, renderer.ImageSize), ...
    "Valid", reshape(valid, renderer.ImageSize));
end

function recommendation = recommendPolicy(results, study)
candidate = results.LabelMode == "projected-motion";
sgm = results(candidate & results.Method == "frozen-SGM", :);
fine = results(candidate & results.Method == "guarded-sublabel", :);
oracle = results(candidate & results.Method == "oracle-discrete", :);
target = unique(sgm.TargetProjectedMotionPixels);
baseline = double(study.baselineTargetProjectedMotionPixels);
summary = zeros(numel(target), 11);
for k = 1:numel(target)
    qs = sgm.TargetProjectedMotionPixels == target(k);
    qf = fine.TargetProjectedMotionPixels == target(k);
    qo = oracle.TargetProjectedMotionPixels == target(k);
    summary(k, :) = [target(k), mean(sgm.EpeRmsePixels(qs)), ...
        max(sgm.EpeRmsePixels(qs)), ...
        mean(fine.EpeRmsePixels(qf)), max(fine.EpeRmsePixels(qf)), ...
        mean(oracle.EpeRmsePixels(qo)), max(oracle.EpeRmsePixels(qo)), ...
        mean(sgm.BoundaryWinnerFraction(qs)), ...
        mean(sgm.Coverage(qs)), mean(fine.Coverage(qf)), ...
        mean(sgm.LabelCount(qs))];
end
summary = array2table(summary, VariableNames=[ ...
    "TargetProjectedMotionPixels", "MeanSgmEpeRmsePixels", ...
    "WorstSgmEpeRmsePixels", "MeanRefinedEpeRmsePixels", ...
    "WorstRefinedEpeRmsePixels", "MeanOracleEpeRmsePixels", ...
    "WorstOracleEpeRmsePixels", "MeanBoundaryWinnerFraction", ...
    "MeanSgmCoverage", "MeanRefinedCoverage", "MeanLabelCount"]);
base = summary.TargetProjectedMotionPixels == baseline;
if nnz(base) ~= 1
    error("runHeightLabelDensityStudy:MissingBaseline", ...
        "The baseline target motion must appear exactly once.");
end
s = study.selection;
summary.FinePass = ...
    summary.MeanRefinedEpeRmsePixels ...
    <= summary.MeanRefinedEpeRmsePixels(base) ...
    + double(s.fineMaximumMeanSceneEpeIncreasePixels) ...
    & summary.WorstRefinedEpeRmsePixels ...
    <= summary.WorstRefinedEpeRmsePixels(base) ...
    + double(s.fineMaximumWorstSceneEpeIncreasePixels) ...
    & summary.WorstOracleEpeRmsePixels ...
    <= selectionValue(s, "fineMaximumWorstOracleEpeRmsePixels", Inf) ...
    & summary.MeanRefinedCoverage ...
    >= summary.MeanRefinedCoverage(base) ...
    - selectionValue(s, "fineMaximumMeanCoverageLoss", Inf) ...
    & summary.MeanBoundaryWinnerFraction ...
    <= double(s.maximumMeanBoundaryWinnerFraction);
summary.CoarsePass = ...
    summary.MeanSgmEpeRmsePixels ...
    <= summary.MeanSgmEpeRmsePixels(base) ...
    + double(s.coarseMaximumMeanSceneEpeIncreasePixels) ...
    & summary.WorstSgmEpeRmsePixels ...
    <= summary.WorstSgmEpeRmsePixels(base) ...
    + double(s.coarseMaximumWorstSceneEpeIncreasePixels) ...
    & summary.WorstOracleEpeRmsePixels ...
    <= selectionValue(s, "coarseMaximumWorstOracleEpeRmsePixels", Inf) ...
    & summary.MeanSgmCoverage >= summary.MeanSgmCoverage(base) ...
    - selectionValue(s, "coarseMaximumMeanCoverageLoss", Inf) ...
    & summary.MeanBoundaryWinnerFraction ...
    <= double(s.maximumMeanBoundaryWinnerFraction);
recommendation = struct( ...
    "TuningSummary", summary, ...
    "RecommendedFineTargetProjectedMotionPixels", ...
    largestPassing(summary.TargetProjectedMotionPixels, summary.FinePass), ...
    "RecommendedCoarseTargetProjectedMotionPixels", ...
    largestPassing(summary.TargetProjectedMotionPixels, summary.CoarsePass), ...
    "SelectionRule", string(s.rule), ...
    "Frozen", false, ...
    "HeldoutAccessed", false);
end

function recommendation = assessFrozenPolicy(results, study)
p = study.frozenPolicy;
coarse = results.TargetProjectedMotionPixels ...
    == double(p.coarseTargetProjectedMotionPixels);
fine = results.TargetProjectedMotionPixels ...
    == double(p.fineTargetProjectedMotionPixels);
recommendation = struct( ...
    "Frozen", true, ...
    "CoarseTargetProjectedMotionPixels", ...
    double(p.coarseTargetProjectedMotionPixels), ...
    "FineTargetProjectedMotionPixels", ...
    double(p.fineTargetProjectedMotionPixels), ...
    "CoarseResults", results(coarse, :), ...
    "FineResults", results(fine, :), ...
    "HeldoutAccessed", true, ...
    "PolicyChangedAfterHeldout", false);
end

function forecast = forecastFullFormat(results, runtime, study, recommendation)
mode = runtime.LabelMode == "projected-motion";
target = unique(runtime.TargetProjectedMotionPixels(mode));
rows = cell(numel(target), 10);
imageSize = double(study.forecast.imageSize);
for k = 1:numel(target)
    q = mode & runtime.TargetProjectedMotionPixels == target(k);
    labelCount = round(median(runtime.LabelCount(q)));
    secondsPerPixelLabel = median(runtime.AlgorithmSeconds(q) ...
        ./ runtime.PixelLabelEvaluations(q));
    estimatedSeconds = prod(imageSize) .* labelCount ...
        .* secondsPerPixelLabel;
    memory = HeightSweepMemoryEstimator.estimate( ...
        imageSize, labelCount, ...
        Precision=string(study.forecast.precision), Mode="streamed", ...
        DirectionCount=double(study.forecast.directionCount), ...
        RowSlabRows=double(study.forecast.rowSlabRows), ...
        Products=string(study.forecast.products));
    resultRows = results(results.LabelMode == "projected-motion" ...
        & results.TargetProjectedMotionPixels == target(k) ...
        & results.Method == "frozen-SGM", :);
    rows(k, :) = {target(k), labelCount, min(runtime.LabelCount(q)), ...
        max(runtime.LabelCount(q)), estimatedSeconds, ...
        memory.RequestedRamBytes ./ 2^30, ...
        memory.PersistentStoreBytes ./ 2^30, ...
        mean(resultRows.EpeRmsePixels), max(resultRows.EpeRmsePixels), ...
        "linear extrapolation from small-scene total seconds per pixel-label"};
end
tableResult = cell2table(rows, VariableNames=[ ...
    "TargetProjectedMotionPixels", "MedianLabelCount", ...
    "MinimumSceneLabelCount", "MaximumSceneLabelCount", ...
    "EstimatedAlgorithmSeconds", "StreamedTrackedRamGiB", ...
    "PersistentCostStoreGiB", "MeanSceneSgmEpeRmsePixels", ...
    "WorstSceneSgmEpeRmsePixels", "RuntimeDefinition"]);
forecast = struct( ...
    "ImageSize", imageSize, ...
    "PixelCount", prod(imageSize), ...
    "Candidates", tableResult, ...
    "Recommendation", recommendation, ...
    "Limit", ...
    "small-scene linear forecast excludes image I/O, RPC cost, and hierarchy overhead");
end

function figures = displayStudy(results, runtime, recommendation, mode)
figures = struct;
figures.Summary = figure(Name="Height-label density study", Color="w");
layout = tiledlayout(figures.Summary, 2, 2, TileSpacing="compact");
q = results.LabelMode == "projected-motion";
methods = unique(results.Method(q), "stable");
ax = nexttile(layout);
hold(ax, "on");
for k = 1:numel(methods)
    r = results(q & results.Method == methods(k), :);
    [x, ~, group] = unique(r.TargetProjectedMotionPixels);
    y = accumarray(group, r.EpeRmsePixels, [], @mean);
    plot(ax, x, y, "-o", DisplayName=methods(k));
end
set(ax, XScale="log"); grid(ax, "on"); legend(ax, Location="best");
xlabel(ax, "Target projected motion (pixels)");
ylabel(ax, "Mean scene EPE RMSE (pixels)"); title(ax, mode + " error");

ax = nexttile(layout);
[x, ~, group] = unique(runtime.TargetProjectedMotionPixels( ...
    runtime.LabelMode == "projected-motion"));
r = runtime(runtime.LabelMode == "projected-motion", :);
plot(ax, x, accumarray(group, r.AlgorithmSeconds, [], @mean), "-o");
set(ax, XScale="log", YScale="log"); grid(ax, "on");
xlabel(ax, "Target projected motion (pixels)");
ylabel(ax, "Mean algorithm seconds"); title(ax, "Runtime");

ax = nexttile(layout);
plot(ax, x, accumarray(group, r.LabelCount, [], @mean), "-o");
set(ax, XScale="log", YScale="log"); grid(ax, "on");
xlabel(ax, "Target projected motion (pixels)");
ylabel(ax, "Mean label count"); title(ax, "Search size");

ax = nexttile(layout);
axis(ax, "off");
if isfield(recommendation, "RecommendedCoarseTargetProjectedMotionPixels")
    text(ax, 0, 0.75, sprintf("Recommended coarse: %.3g px", ...
        recommendation.RecommendedCoarseTargetProjectedMotionPixels));
    text(ax, 0, 0.55, sprintf("Recommended fine: %.3g px", ...
        recommendation.RecommendedFineTargetProjectedMotionPixels));
else
    text(ax, 0, 0.75, sprintf("Frozen coarse: %.3g px", ...
        recommendation.CoarseTargetProjectedMotionPixels));
    text(ax, 0, 0.55, sprintf("Frozen fine: %.3g px", ...
        recommendation.FineTargetProjectedMotionPixels));
end
title(ax, "Policy");
end

function printStudy(report)
fprintf("\nHeight-label density study: %s (%s)\n", ...
    report.StudyIdentifier, report.Mode);
disp(report.SceneDiagnostics);
if report.Mode == "tuning"
    disp(report.Recommendation.TuningSummary);
    fprintf("  recommended coarse/fine target motion: %.6g / %.6g pixels\n", ...
        report.Recommendation.RecommendedCoarseTargetProjectedMotionPixels, ...
        report.Recommendation.RecommendedFineTargetProjectedMotionPixels);
else
    fprintf("  assessed frozen coarse/fine target motion: %.6g / %.6g pixels\n", ...
        report.Recommendation.CoarseTargetProjectedMotionPixels, ...
        report.Recommendation.FineTargetProjectedMotionPixels);
end
disp(report.FullFormatForecast.Candidates);
fprintf("  total %.3f s; held-out accessed: %s\n\n", ...
    report.TotalSeconds, string(report.HeldoutAccessed));
end

function bins = tertileBins(value, valid)
x = value(valid & isfinite(value));
bins = zeros(size(value));
if isempty(x)
    return
end
edge = [finitePercentile(x, 100 / 3), finitePercentile(x, 200 / 3)];
bins(valid & isfinite(value) & value <= edge(1)) = 1;
bins(valid & isfinite(value) & value > edge(1) & value <= edge(2)) = 2;
bins(valid & isfinite(value) & value > edge(2)) = 3;
end

function bins = boundaryBins(value, valid)
bins = zeros(size(value));
bins(valid & value <= 2) = 1;
bins(valid & value > 2 & value <= 5) = 2;
bins(valid & value > 5) = 3;
end

function truth = truthWithValid(truth, valid)
truth.Valid = valid;
end

function value = largestPassing(target, pass)
value = max(target(pass), [], "omitmissing");
if isempty(value) || ~isfinite(value)
    value = min(target);
end
end

function value = selectionValue(selection, name, fallback)
if isfield(selection, name)
    value = double(selection.(name));
else
    value = fallback;
end
end

function path = resolveFixture(folder, name)
if isfile(name)
    path = name;
else
    path = fullfile(folder, name);
end
if ~isfile(path)
    error("runHeightLabelDensityStudy:FixtureNotFound", ...
        "Fixture does not exist: %s", path);
end
end

function validateStudy(study)
required = ["identifier", "state", "tuningFixtures", ...
    "heldoutFixtures", "targetProjectedMotionPixels", ...
    "includeThreePlaneControl", "baselineTargetProjectedMotionPixels", ...
    "dense", "sgm", "metrics", "selection", "forecast"];
if ~all(isfield(study, required))
    error("runHeightLabelDensityStudy:InvalidStudy", ...
        "Study manifest is missing one or more required fields.");
end
if ismember(string(study.state), ...
        ["policy-frozen", "failure-diagnostics-preregistered"]) ...
        && ~isfield(study, "frozenPolicy")
    error("runHeightLabelDensityStudy:InvalidStudy", ...
        "A policy-frozen manifest must contain frozenPolicy.");
end
if string(study.state) == "failure-diagnostics-preregistered" ...
        && ~isfield(study, "failureDetection")
    error("runHeightLabelDensityStudy:InvalidStudy", ...
        "A failure-diagnostics manifest must contain failureDetection.");
end
target = double(study.targetProjectedMotionPixels(:));
if isempty(target) || any(~isfinite(target) | target <= 0) ...
        || numel(unique(target)) ~= numel(target)
    error("runHeightLabelDensityStudy:InvalidTargets", ...
        "Projected-motion targets must be unique, finite, and positive.");
end
end

function value = finiteStatistic(x, operation)
x = x(isfinite(x));
if isempty(x)
    value = NaN;
else
    value = operation(x);
end
end

function value = finitePercentile(x, q)
x = sort(x(isfinite(x)));
if isempty(x)
    value = NaN;
    return
end
position = 1 + (numel(x) - 1) .* q ./ 100;
lo = floor(position);
hi = ceil(position);
value = x(lo) + (position - lo) .* (x(hi) - x(lo));
end

function n = precisionBytes(name)
if name == "single"
    n = 4;
else
    n = 8;
end
end
